func openSession(id string, name string, state string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_openSession_f492`,
		Function: `function __templ_openSession_f492(id, name, state){window.websessions.openTab(id, name, state);
}`,
		Call:       templ.SafeScript(`__templ_openSession_f492`, id, name, state),
		CallInline: templ.SafeScriptInline(`__templ_openSession_f492`, id, name, state),
	}
}

func stateClass(state string) string {
	switch state {
	case "running":
		return "state-running"
	case "completed":
		return "state-completed"
	case "errored":
		return "state-errored"
	case "waiting":
		return "state-waiting"
	case "discovered":
		return "state-discovered"
	case "offline":
		return "state-offline"
	case "killed":
		return "state-errored"
	default:
		return ""
	}
}

func isFirstInGroup(s SessionView, sessions []SessionView) bool {
	for _, other := range sessions {
		if other.GroupName == s.GroupName {
			return other.ID == s.ID
		}
	}
	return false
}

func sessionsInGroup(groupName string, sessions []SessionView) []SessionView {
	var result []SessionView
	for _, s := range sessions {
		if s.GroupName == groupName {
			result = append(result, s)
		}
	}
	return result
}

func countInGroup(groupName string, sessions []SessionView) int {
	count := 0
	for _, s := range sessions {
		if s.GroupName == groupName {
			count++
		}
	}
	return count
}

